buttonColor:
{{
  (() => {
    // 1. Spaltennamen anpassen
    const ventSpalte = "Ventil_Rechts"; 
    const leerSpalte = "Status_Leer_Rechts";

    const rawVal = String(currentItem[ventSpalte] || "").trim();
    if (!rawVal) return '#3b82f6';

    // 2. PRÜFUNG: Stammdaten "Leer"-Status
    // Wir suchen nach der exakten Zeile in Stammdaten
    const stammdatenEintrag = (Stammdaten.data || []).find(row => 
        String(row[ventSpalte] || "").trim() === rawVal
    );

    // Prüfe auf TRUE (als Boolean oder String)
    if (stammdatenEintrag && 
       (stammdatenEintrag[leerSpalte] === true || String(stammdatenEintrag[leerSpalte]).toUpperCase() === "TRUE")) {
        return '#e5e7eb'; // Grau
    }

    // 3. Restliche Logik (wie bisher)
    const btnVal = parseFloat(rawVal).toFixed(2);

    const alleEintraege = (Bewaesserung_Lesen.data || []).filter(row => {
        return parseFloat(row.Ventil || 0).toFixed(2) === btnVal;
    });

    if (alleEintraege.length > 0) {
        alleEintraege.sort((a, b) => {
            const dateA = new Date(a.Zeitstempel.split(' ')[0].split('.').reverse().join('-'));
            const dateB = new Date(b.Zeitstempel.split(' ')[0].split('.').reverse().join('-'));
            return dateB - dateA;
        });

        const latest = alleEintraege[0];
        const dateLatest = new Date(latest.Zeitstempel.split(' ')[0].split('.').reverse().join('-'));
        const heute = new Date();

        const istHeute = (
            dateLatest.getDate() === heute.getDate() &&
            dateLatest.getMonth() === heute.getMonth() &&
            dateLatest.getFullYear() === heute.getFullYear()
        );

        if (!istHeute) return '#3b82f6';
        if (String(latest.Status || "").toLowerCase().includes("fertig")) return '#22c55e';

        const m = String(latest.Modus || "").toLowerCase();
        if (m.includes("jetzt"))  return '#991b1b';
        if (m.includes("später")) return '#f97316';
        if (m.includes("zeit"))   return '#f87171';
    }

    return '#3b82f6';
  })()
}}

