text:
{{
  (() => {
    // 1. Ventil identifizieren
    const rawVal = String(currentItem.Ventil_Rechts || "").trim();
    const btnVal = parseFloat(rawVal).toFixed(2);

    // 2. Leer-Status prüfen
    if (appsmith.store['Ventil_Leer_' + btnVal]) {
      return btnVal;
    }

    // 3. Alle Einträge für dieses Ventil filtern
    const filter = (Bewaesserung_Lesen.data || []).filter(row => 
      parseFloat(row.Ventil || 0).toFixed(2) === btnVal
    );

    // Ventilname formatieren
    const formattedName = btnVal.startsWith("2") ? "2. " + btnVal : btnVal;

    // 4. Tage-Berechnung über unser zentrales Helper-Objekt
    if (filter.length === 0) return formattedName;

    // getTageHer gibt "Heute", "1 Tag her", "2 Tage her" etc. zurück
    const statusText = Data_Helper.getTageHer(filter);

    return `${formattedName} (${statusText})`;
  })()
}}
